{
  if (!Phi->hasOneUse())
    return nullptr;

  auto *BinOp = dyn_cast<BinaryOperator>(*Phi->user_begin());
  if (!BinOp)
    return nullptr;

  // We only handle integer and float recurrences.
  if (!Phi->getType()->isIntegerTy() && !Phi->getType()->isFloatTy())
    return nullptr;

  Value *RdxOp = (BinOp->getOperand(0) == Phi) ? BinOp->getOperand(1)
                                              : BinOp->getOperand(0);

  // If the other operand is the identity constant, this is not a reduction.
  if (auto *CI = dyn_cast<Constant>(RdxOp)) {
    if (Instruction::isAssociative(BinOp->getOpcode()) &&
        Instruction::isCommutative(BinOp->getOpcode())) {
      if (Constant *Id =
