  // users. We support this only if the other users are the loop exit test.
  for (User *U : BinOp->users())
    if (U != Phi && !isLoopExit(U))
      return nullptr;

  // The user of the phi node must be a binary operator.
  Instruction::BinaryOps Opc = BinOp->getOpcode();
  if (!Instruction::isBinaryOp(Opc))
    return nullptr;

  // We can only handle recurrences that are associative and commutative.
